mapper.select:
SELECT id, user_id as userId, name, normalized_name as normalizedName, quantity, unit, type
FROM user_ingredients
WHERE user_id = #{userId}

    AND type = #{type}

AND deleted_at IS NULL
ORDER BY created_at DESC

mapper.update:
UPDATE user_ingredients
SET quantity = #{quantity},
    updated_at = NOW()
WHERE user_id = #{userId}
AND normalized_name = #{normalizedName}
AND deleted_at IS NULL

UPDATE user_ingredients
SET deleted_at = NOW()
WHERE id = #{id}
AND user_id = #{userId}
